from __future__ import annotations
EVIDENCE_TYPES_4 = ['episode', 'theme', 'focal', 'prior_event']
HYPOTHESIS_EXTRACT_PROMPT = 'Extract a STRUCTURED HYPOTHESIS from this causal SKILL.\n\nSKILL\n  name: {skill_name}\n  description: {skill_description}\n  domain: {skill_domain}\n\nFIELDS TO EXTRACT\n  - predicate: a falsifiable IF-THEN pattern in ≤120 chars\n    Example: "IF analyst rating upgrade AND no concurrent negative events THEN positive 5-day return"\n  - target_evidence_types: which evidence types should be retrieved to test this skill.\n    Choose 2-4 from: "focal", "prior_event", "episode", "theme".\n    "focal" = the event\'s own announcement; "prior_event" = past events on same stock;\n    "episode" = 7-14d causal chains on this stock; "theme" = cross-stock thematic patterns.\n  - expected_direction: "positive" or "negative" — what this skill predicts IF the pattern holds.\n\nCRITICAL: Output VALID JSON ONLY, no markdown, no preamble. Start with `{{`, end with `}}`.\n\n{{"predicate": "<IF X THEN Y, ≤120 chars>",\n  "target_evidence_types": ["focal", "prior_event"],\n  "expected_direction": "positive"}}'
PATH_REASONING_PROMPT = 'You are a critical financial analyst testing whether a causal SKILL applies to a specific corporate event, then forecasting the 5-day return direction.\n\nSKILL UNDER TEST\n  name: {skill_name}\n  description: {skill_description}\n  predicate: {hypothesis_predicate}\n  expected_direction (from skill, may be wrong here): {expected_direction}\n\nEVENT TO PREDICT\n  {event_text}\n\nRETRIEVED EVIDENCE (filtered by skill\'s target evidence types)\n{evidence_block}\n\nREASONING STEPS (be CRITICAL — do not rubber-stamp the skill\'s expected_direction):\n  Step 1. Is this skill RELEVANT to this specific event? (relevance ≠ correctness)\n  Step 2. Does the EVIDENCE support, contradict, or fail to inform the skill\'s pattern on this event?\n  Step 3. Are there event-specific factors (magnitude, timing, sentiment, concurrent context) that override the general pattern?\n  Step 4. Decide:\n     - If evidence supports skill → y_i = skill\'s expected direction\n     - If evidence contradicts → y_i = OPPOSITE of skill\'s expected direction\n     - If skill is irrelevant OR evidence too thin to judge → y_i = "abstain" (set support_i = 0.0)\n  Step 5. support_i ∈ [0, 1] = how confident THIS PATH\'s prediction is right (0.0 for abstain, 0.5 for low-conf, 0.9 for high-conf).\n\nCRITICAL: Output VALID JSON ONLY, no markdown, no preamble, no extra text.\nThe response MUST start with `{{` and end with `}}`.\n\n{{"y_i": "positive" or "negative" or "abstain",\n  "support_i": <float between 0 and 1>,\n  "rationale_i": "<one concise sentence, ≤150 chars>"}}'